// COHORT CONFIGURATION - Update these values for each automation
const COHORT_CONFIG = {
  name: "Day3 cohort - all ACTIVEs till date",
  cohortId: "5822925",
  heyreachListId: 324814,
  sheetTabName: "Day3 cohort - all ACTIVEs till date"
};

return [{json: COHORT_CONFIG}];

// Parse all Mixpanel users - NO FILTERING
const users = items[0].json.results || [];
const cohortConfig = $('Cohort Configuration').first().json;

const processed = users.map(user => {
  let email = (user.properties && user.properties.$email) ? user.properties.$email : user.$distinct_id;
  email = (email || '').toLowerCase().trim();

  const [namePart, companyPart] = email.split('@');
  const firstName = namePart ? namePart.split(/[._]/)[0] : '';
  const companyGuess = companyPart ? companyPart.split('.')[0] : '';

  return { 
    Email: email,
    firstName: firstName,
    companyGuess: companyGuess,
    Mixpanel_ID: user.$distinct_id || email,
    Current_Cohort_Name: cohortConfig.name,
    Current_Cohort_ID: cohortConfig.cohortId,
    heyreachListId: cohortConfig.heyreachListId,
    cohortTabName: cohortConfig.sheetTabName,
    Added_To_This_Cohort_Date: new Date().toISOString().split('T')[0]
  };
});

return processed.map(user => ({ json: user }));

// Check if this user was previously enriched in Master Sheet
// This node receives merged data from: Mixpanel Users + Master Sheet lookup
const item = $input.item.json;

// Determine if user has Apollo enrichment data from Master Sheet
const hasApolloData = !!(
  item.Apollo_Person_ID && 
  item.Apollo_Person_ID.trim() !== ''
);

// Determine if user exists in Master Sheet (has any Master Sheet fields)
const existsInMasterSheet = !!(
  item.First_Seen_Cohort || 
  item.Enrichment_Date ||
  item.Last_Updated
);

// Determine if already sent to HeyReach in a previous cohort
const alreadySentToHeyreach = (
  item.HeyReach_Status === 'Sent' || 
  (item.HeyReach_Status && item.HeyReach_Status.includes('Already Sent'))
);

// Get previous cohort info if exists
const previousCohort = item.Last_Seen_Cohort || item.First_Seen_Cohort || '';

// Build output with ALL necessary fields
const output = {
  // ========== PRIMARY IDENTIFIERS ==========
  Email: item.Email || '',
  Mixpanel_ID: item.Mixpanel_ID || '',

  // ========== NAME & COMPANY ==========
  First_Name: hasApolloData ? (item.First_Name || '') : (item.firstName || ''),
  Last_Name: hasApolloData ? (item.Last_Name || '') : '',
  Company_Name: hasApolloData ? (item.Company_Name || '') : (item.companyGuess || ''),
  Company_Size: hasApolloData ? (item.Company_Size || 0) : 0,

  // ========== PROFESSIONAL INFO (from Apollo) ==========
  LinkedIn_URL: hasApolloData ? (item.LinkedIn_URL || '') : '',
  Title: hasApolloData ? (item.Title || '') : '',
  Department: hasApolloData ? (item.Department || '') : '',
  Location: hasApolloData ? (item.Location || '') : '',
  Lead_Score: hasApolloData ? (item.Lead_Score || 0) : 0,
  Persona_Category: hasApolloData ? (item.Persona_Category || 'Unknown') : 'Unknown',
  Match_Confidence: hasApolloData ? (item.Match_Confidence || 0) : 0,

  // ========== APOLLO TRACKING ==========
  Apollo_Person_ID: hasApolloData ? (item.Apollo_Person_ID || '') : '',
  Source_Company_apolloOrgId: hasApolloData ? (item.Source_Company_apolloOrgId || '') : '',
  Enrichment_Date: hasApolloData ? (item.Enrichment_Date || '') : '',
  Enrichment_Status: hasApolloData ? 'Enriched' : 'Not Enriched',

  // ========== COHORT TRACKING ==========
  First_Seen_Cohort: item.First_Seen_Cohort || item.Current_Cohort_Name || '',
  First_Seen_Date: item.First_Seen_Date || item.Added_To_This_Cohort_Date || '',
  Last_Seen_Cohort: item.Current_Cohort_Name || '',
  Last_Seen_Date: item.Added_To_This_Cohort_Date || '',
  Previous_Cohort: previousCohort,

  // ========== HEYREACH TRACKING ==========
  HeyReach_Status: alreadySentToHeyreach 
    ? `Already Sent in '${previousCohort}' cohort` 
    : 'Pending',
  First_HeyReach_List_ID: item.First_HeyReach_List_ID || '',
  First_Sent_Date: item.First_Sent_Date || '',
  Current_HeyReach_List_ID: item.heyreachListId || '',

  // ========== MIXPANEL DATA (from current cohort) ==========
  Current_Cohort_Name: item.Current_Cohort_Name || '',
  Current_Cohort_ID: item.Current_Cohort_ID || '',
  Added_To_This_Cohort_Date: item.Added_To_This_Cohort_Date || '',

  // ========== METADATA ==========
  Last_Updated: new Date().toISOString().split('T')[0],

  // ========== CONTROL FLAGS ==========
  needsApolloEnrichment: !hasApolloData,  // TRUE if needs Apollo call
  skipHeyreach: alreadySentToHeyreach,    // TRUE if already sent before
  wasEnriched: hasApolloData,             // TRUE if has Apollo data
  isNewUser: !existsInMasterSheet,        // TRUE if not in Master Sheet

  // ========== DATA FOR APOLLO CALL (if needed) ==========
  firstName: item.firstName || item.First_Name || '',
  companyGuess: item.companyGuess || item.Company_Name || '',
  heyreachListId: item.heyreachListId || '',
  cohortTabName: item.cohortTabName || item.Current_Cohort_Name || ''
};

return { json: output };

// Process Apollo enrichment and score leads with ICP logic
const items = $input.all();
const results = [];

items.forEach(item => {
  const itemData = item.json;
  const apolloData = itemData.person || {};

  // Get email from correct location
  const userEmail = itemData.email || itemData.Email || apolloData.email || '';

  // CRITICAL: Preserve Mixpanel_ID
  const mixpanelId = itemData.Mixpanel_ID || itemData.mixpanelId || '';

  // ========== ICP SCORING LOGIC ==========
  const title = (apolloData.title || '').toLowerCase();
  const departments = (apolloData.departments || []).join(' ').toLowerCase();
  const companySize = apolloData.organization?.estimated_num_employees || 0;

  let score = 1;
  let persona = 'Unknown';

  // Score 5: RevOps/Marketing Ops
  if (title.includes('revenue operations') || title.includes('revops') || title.includes('rev ops') ||
      title.includes('marketing operations') || title.includes('marketing ops') || title.includes('mops')) {
    score = 5;
    persona = 'RevOps/Marketing Ops';
  }
  // Score 4: Data/Analytics
  else if (title.includes('data analyst') || title.includes('analytics manager') ||
           title.includes('business analyst') || title.includes('product analyst') ||
           title.includes('data scientist') || departments.includes('analytics') || departments.includes('data')) {
    score = 4;
    persona = 'Data/Analytics';
  }
  // Score 4: Founders/Leadership in Small Companies
  else if ((title.includes('founder') || title.includes('co-founder')) && companySize < 500) {
    score = 4;
    persona = 'Founder/Leadership';
  }
  else if (title.includes('ceo') && companySize < 100) {
    score = 4;
    persona = 'Founder/Leadership';
  }
  else if (title.includes('vp') && companySize < 50) {
    score = 4;
    persona = 'Founder/Leadership';
  }
  // Score 3: Business Operations
  else if (title.includes('business operations') || title.includes('operations manager') ||
           departments.includes('operations')) {
    score = 3;
    persona = 'Business Operations';
  }
  // Score 2: Adjacent Roles
  else if (title.includes('manager') || title.includes('director') ||
           title.includes('product') || title.includes('sales ops')) {
    score = 2;
    persona = 'Adjacent Role';
  }

  // Build output - START WITH ALL ORIGINAL DATA, then override with Apollo data
  const output = {
    // ========== COPY ALL ORIGINAL FIELDS FIRST ==========
    ...itemData,

    // ========== OVERRIDE WITH APOLLO DATA ==========
    Email: userEmail,
    Mixpanel_ID: mixpanelId,
    First_Name: apolloData.first_name || itemData.First_Name || itemData.firstName || '',
    Last_Name: apolloData.last_name || itemData.Last_Name || '',
    Company_Name: apolloData.organization?.name || itemData.Company_Name || itemData.companyGuess || '',
    Company_Size: companySize,
    LinkedIn_URL: apolloData.linkedin_url || itemData.LinkedIn_URL || '',
    Title: apolloData.title || '',
    Department: (apolloData.departments || []).join(', '),
    Location: apolloData.city ? `${apolloData.city}, ${apolloData.state || ''}` : '',
    Lead_Score: score,
    Persona_Category: persona,
    Match_Confidence: apolloData.matched_confidence || 0,
    Apollo_Person_ID: apolloData.id || '',
    Source_Company_apolloOrgId: apolloData.organization?.id || '',
    Enrichment_Date: new Date().toISOString().split('T')[0],
    Enrichment_Status: 'Enriched',
    Last_Updated: new Date().toISOString().split('T')[0],
    needsApolloEnrichment: false,
    wasEnriched: true
  };

  // Remove the Apollo API response fields that shouldn't go to Google Sheets
  delete output.person;
  delete output.employment_history;
  delete output.headline;
  delete output.photo_url;
  delete output.twitter_url;
  delete output.github_url;
  delete output.facebook_url;
  delete output.extrapolated_email_confidence;

  results.push({ json: output });
});

return results;

// Prepare HeyReach status update for Master Sheet
const item = $input.item.json;
const currentDate = new Date().toISOString().split('T')[0];

return {
  Email: item.Email,
  HeyReach_Status: 'Sent',
  First_HeyReach_List_ID: item.First_HeyReach_List_ID || item.heyreachListId || item.Current_HeyReach_List_ID,
  First_Sent_Date: item.First_Sent_Date || currentDate,
  Current_HeyReach_List_ID: item.heyreachListId || item.Current_HeyReach_List_ID,
  Last_Updated: currentDate
};

// Process expansion leads from Apollo search
const originalUser = items[0].json;
const searchResults = items[0].json.people || [];
const processedLeads = [];

function shouldIncludeLeader(title, companySize) {
  const t = title.toLowerCase();
  if (companySize < 500 && (t.includes('founder') || t.includes('co-founder'))) return true;
  if (companySize < 100 && t.includes('ceo')) return true;
  if (companySize < 50 && t.includes('vp')) return true;
  return false;
}

for (const person of searchResults) {
  // Skip if it's the same person
  if (person.email && person.email.toLowerCase() === originalUser.Email.toLowerCase()) continue;

  // Only process if they have LinkedIn URL
  if (!person.linkedin_url) continue;

  const title = (person.title || '').toLowerCase();
  const departments = (person.departments || []).join(' ').toLowerCase();
  const companySize = person.organization?.estimated_num_employees || 0;

  let score = 0;
  let persona = 'Other';

  // Apply ICP scoring
  if (title.includes('revenue operations') || title.includes('revops') ||
      title.includes('marketing operations') || title.includes('marketing ops')) {
    score = 5;
    persona = 'RevOps/Marketing Ops';
  }
  else if (title.includes('data analyst') || title.includes('analytics') ||
           title.includes('business analyst') || title.includes('product analyst')) {
    score = 4;
    persona = 'Data/Analytics';
  }
  else if (shouldIncludeLeader(title, companySize)) {
    score = 4;
    persona = 'Founder/Leadership';
  }
  else if (title.includes('business operations')) {
    score = 3;
    persona = 'Business Operations';
  }
  else {
    score = 2;
    persona = 'Adjacent Role';
  }

  // Bonus if same department
  if (originalUser.Department && departments.includes(originalUser.Department.toLowerCase())) {
    score = Math.min(5, score + 1);
  }

  processedLeads.push({
    json: {
      Email: person.email || '',
      First_Name: person.first_name || '',
      Last_Name: person.last_name || '',
      Company_Name: person.organization?.name || originalUser.Company_Name,
      Company_Size: companySize,
      LinkedIn_URL: person.linkedin_url,
      Title: person.title || '',
      Department: (person.departments || []).join(', '),
      Location: person.city ? `${person.city}, ${person.state || ''} ${person.country || ''}`.trim() : '',
      Lead_Score: score,
      Persona_Category: persona,
      Reference_User_Email: originalUser.Email,
      Reference_User_Mixpanel_ID: originalUser.Mixpanel_ID,
      Reference_User_Name: originalUser.First_Name,
      Reference_User_Cohort: originalUser.Current_Cohort_Name,
      Source_Company_apolloOrgId: originalUser.Source_Company_apolloOrgId,
      Apollo_Person_ID: person.id || '',
      Enrichment_Date: new Date().toISOString().split('T')[0],
      HeyReach_Status: 'Pending',
      Last_Updated: new Date().toISOString().split('T')[0]
    }
  });
}

// Return top 3 by score
processedLeads.sort((a, b) => b.json.Lead_Score - a.json.Lead_Score);
return processedLeads.slice(0, 3);
